/**
 * useRealtimeAlerts
 * -----------------
 * Subscribes to live inventory events using two strategies:
 *
 * 1. Supabase Realtime  — if REACT_APP_SUPABASE_URL is configured, listens to
 *    postgres_changes on the items table (requires Realtime enabled in Supabase).
 *
 * 2. SSE fallback       — connects to GET /events/stream on the FastAPI backend.
 *    Works without Supabase. Receives low_stock, stock_recovered, and audit events.
 *
 * Returns: { alerts, auditFeed, clearAlerts, connected }
 *   alerts    — array of unread low-stock alert objects
 *   auditFeed — last 20 audit events received over the wire
 *   clearAlerts — call to dismiss all alerts
 *   connected — boolean, true when SSE/Realtime is live
 */

import { useEffect, useRef, useState, useCallback } from 'react';
import { supabase } from '../supabaseClient';

const SSE_URL = `${process.env.REACT_APP_API_URL || 'http://localhost:8000'}/events/stream`;
const MAX_AUDIT_FEED = 20;

export function useRealtimeAlerts() {
  const [alerts, setAlerts]       = useState([]);
  const [auditFeed, setAuditFeed] = useState([]);
  const [connected, setConnected] = useState(false);
  const esRef = useRef(null);

  const addAlert = useCallback((alert) => {
    setAlerts((prev) => {
      // Deduplicate by item_id — keep the latest
      const filtered = prev.filter((a) => a.item_id !== alert.item_id);
      return [alert, ...filtered].slice(0, 10);
    });
  }, []);

  const removeAlert = useCallback((itemId) => {
    setAlerts((prev) => prev.filter((a) => a.item_id !== itemId));
  }, []);

  const clearAlerts = useCallback(() => setAlerts([]), []);

  const addAuditEntry = useCallback((entry) => {
    setAuditFeed((prev) => [entry, ...prev].slice(0, MAX_AUDIT_FEED));
  }, []);

  // ── Strategy 1: Supabase Realtime ─────────────────────────────────────────
  useEffect(() => {
    if (!supabase) return; // no Supabase config — skip

    const channel = supabase
      .channel('inventory-changes')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'items' },
        (payload) => {
          const row = payload.new || payload.old;
          if (!row) return;

          if (payload.eventType === 'UPDATE' || payload.eventType === 'INSERT') {
            if (row.stock_count < 10) {
              addAlert({
                item_id:     row.id,
                item_name:   row.name,
                stock_count: row.stock_count,
                location:    row.location,
                timestamp:   new Date().toISOString(),
                source:      'realtime',
              });
            }
          }
        }
      )
      .subscribe((status) => {
        setConnected(status === 'SUBSCRIBED');
      });

    return () => {
      supabase.removeChannel(channel);
    };
  }, [addAlert]);

  // ── Strategy 2: SSE fallback ──────────────────────────────────────────────
  useEffect(() => {
    // If Supabase is configured and connected, SSE is still useful for audit events
    // so we always open it.
    let retryTimeout;

    function connect() {
      if (esRef.current) {
        esRef.current.close();
      }

      const es = new EventSource(SSE_URL);
      esRef.current = es;

      es.addEventListener('open', () => {
        if (!supabase) setConnected(true);
      });

      es.addEventListener('low_stock', (e) => {
        try {
          const data = JSON.parse(e.data);
          addAlert({ ...data, source: 'sse' });
        } catch {}
      });

      es.addEventListener('stock_recovered', (e) => {
        try {
          const data = JSON.parse(e.data);
          removeAlert(data.item_id);
        } catch {}
      });

      es.addEventListener('audit', (e) => {
        try {
          const data = JSON.parse(e.data);
          addAuditEntry(data);
        } catch {}
      });

      es.addEventListener('heartbeat', () => {
        if (!supabase) setConnected(true);
      });

      es.onerror = () => {
        es.close();
        if (!supabase) setConnected(false);
        // Reconnect after 5s
        retryTimeout = setTimeout(connect, 5000);
      };
    }

    connect();

    return () => {
      clearTimeout(retryTimeout);
      esRef.current?.close();
      esRef.current = null;
    };
  }, [addAlert, removeAlert, addAuditEntry]);

  return { alerts, auditFeed, clearAlerts, connected };
}
